import{_ as d,o as e,c as r,ag as o}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Command Reference","description":"","frontmatter":{},"headers":[],"relativePath":"commands/index.md","filePath":"commands/index.md"}'),a={name:"commands/index.md"};function n(c,t,l,i,s,m){return e(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="command-reference" tabindex="-1">Command Reference <a class="header-anchor" href="#command-reference" aria-label="Permalink to &quot;Command Reference&quot;">​</a></h1><p>Complete list of all R3 commands organized by permission level. Commands use <code>!</code> for private response, <code>@</code> for public response, or <code>&amp;</code> for bigtext.</p><h2 id="guest-level-0" tabindex="-1">Guest (Level 0) <a class="header-anchor" href="#guest-level-0" aria-label="Permalink to &quot;Guest (Level 0)&quot;">​</a></h2><p>Available to all players.</p><table tabindex="0"><thead><tr><th>Command</th><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><code>!help</code></td><td>admin</td><td>Lists commands available at your level</td></tr><tr><td><code>!leveltest [player]</code></td><td>admin</td><td>Shows your or a player&#39;s group and level</td></tr><tr><td><code>!time</code></td><td>admin</td><td>Shows current server time (UTC)</td></tr><tr><td><code>!register</code> / <code>!regme</code></td><td>admin</td><td>Self-register as User (level 1)</td></tr><tr><td><code>!r3</code></td><td>admin</td><td>Shows R3 version information</td></tr><tr><td><code>!stats</code></td><td>stats</td><td>Shows your kills, deaths, K/D ratio</td></tr><tr><td><code>!topstats</code></td><td>stats</td><td>Shows top 5 players by kills</td></tr><tr><td><code>!xlrstats</code> / <code>!xlr</code></td><td>xlrstats</td><td>Shows your XLR stats and skill rating</td></tr><tr><td><code>!xlrtopstats</code></td><td>xlrstats</td><td>Shows top ranked players</td></tr><tr><td><code>!hs</code> / <code>!headshots [player]</code></td><td>headshotcounter</td><td>Shows headshot stats</td></tr><tr><td><code>!login &lt;password&gt;</code></td><td>login</td><td>Authenticates with admin password</td></tr><tr><td><code>!setpassword &lt;password&gt;</code></td><td>login</td><td>Sets/changes admin password</td></tr><tr><td><code>!follow &lt;player&gt;</code></td><td>follow</td><td>Start following a player</td></tr><tr><td><code>!unfollow &lt;player&gt;</code></td><td>follow</td><td>Stop following a player</td></tr><tr><td><code>!&lt;custom&gt;</code></td><td>customcommands</td><td>Any user-defined command</td></tr></tbody></table><h2 id="user-level-1" tabindex="-1">User (Level 1) <a class="header-anchor" href="#user-level-1" aria-label="Permalink to &quot;User (Level 1)&quot;">​</a></h2><p>Registered players.</p><table tabindex="0"><thead><tr><th>Command</th><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><code>!regulars</code></td><td>admin</td><td>Lists online Regular+ players</td></tr><tr><td><code>!rules [player]</code></td><td>admin</td><td>Shows server rules</td></tr></tbody></table><h2 id="moderator-level-20" tabindex="-1">Moderator (Level 20) <a class="header-anchor" href="#moderator-level-20" aria-label="Permalink to &quot;Moderator (Level 20)&quot;">​</a></h2><p>Can manage players and issue warnings.</p><table tabindex="0"><thead><tr><th>Command</th><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><code>!status</code></td><td>admin</td><td>Connected players with slot, name, ID, level</td></tr><tr><td><code>!list</code></td><td>admin</td><td>Compact player list</td></tr><tr><td><code>!lookup &lt;name&gt;</code></td><td>admin</td><td>Search database for players</td></tr><tr><td><code>!find &lt;name&gt;</code></td><td>admin</td><td>Find connected players by name</td></tr><tr><td><code>!admins</code></td><td>admin</td><td>List online admins</td></tr><tr><td><code>!warn &lt;player&gt; [reason/keyword]</code></td><td>admin</td><td>Warn a player</td></tr><tr><td><code>!kick &lt;player&gt; [reason]</code></td><td>admin</td><td>Kick a player</td></tr><tr><td><code>!spank &lt;player&gt; [reason]</code></td><td>admin</td><td>Kick with public humiliation</td></tr><tr><td><code>!seen &lt;name&gt;</code></td><td>admin</td><td>When was a player last online</td></tr><tr><td><code>!aliases &lt;name or @id&gt;</code></td><td>admin</td><td>Player&#39;s name history</td></tr><tr><td><code>!poke &lt;player&gt;</code></td><td>admin</td><td>Send attention message</td></tr><tr><td><code>!notice &lt;player&gt; &lt;text&gt;</code></td><td>admin</td><td>Add note to player&#39;s record</td></tr><tr><td><code>!clear &lt;player&gt;</code></td><td>admin</td><td>Clear all warnings and notices</td></tr><tr><td><code>!warns</code></td><td>admin</td><td>List warn keywords</td></tr><tr><td><code>!warntest &lt;keyword&gt;</code></td><td>admin</td><td>Test a warn keyword</td></tr><tr><td><code>!warnremove &lt;player&gt;</code></td><td>admin</td><td>Remove last warning</td></tr><tr><td><code>!warninfo &lt;player&gt;</code></td><td>admin</td><td>Show warning count</td></tr><tr><td><code>!ident [player]</code> / <code>!id</code></td><td>poweradminurt</td><td>Show player @id</td></tr></tbody></table><h2 id="admin-level-40" tabindex="-1">Admin (Level 40) <a class="header-anchor" href="#admin-level-40" aria-label="Permalink to &quot;Admin (Level 40)&quot;">​</a></h2><p>Can tempban and use advanced server commands.</p><table tabindex="0"><thead><tr><th>Command</th><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><code>!tempban &lt;player&gt; [duration] [reason]</code></td><td>admin</td><td>Temporary ban (Nm/Nh/Nd/Nw)</td></tr><tr><td><code>!lastbans</code></td><td>admin</td><td>Show 5 most recent bans</td></tr><tr><td><code>!baninfo &lt;player&gt;</code></td><td>admin</td><td>Show ban count</td></tr><tr><td><code>!spam &lt;keyword&gt; [player]</code></td><td>admin</td><td>Send predefined message</td></tr><tr><td><code>!spams</code></td><td>admin</td><td>List spam keywords</td></tr><tr><td><code>!clientinfo &lt;name or @id&gt;</code></td><td>admin</td><td>Detailed client info</td></tr><tr><td><code>!slap &lt;player&gt; [count]</code></td><td>poweradminurt</td><td>Slap a player (max 25)</td></tr><tr><td><code>!nuke &lt;player&gt;</code></td><td>poweradminurt</td><td>Nuke a player</td></tr><tr><td><code>!mute &lt;player&gt; [seconds]</code></td><td>poweradminurt</td><td>Mute a player</td></tr><tr><td><code>!kill &lt;player&gt;</code></td><td>poweradminurt</td><td>Smite a player</td></tr><tr><td><code>!force &lt;player&gt; &lt;team&gt;</code></td><td>poweradminurt</td><td>Force to red/blue/spec/free</td></tr><tr><td><code>!swap &lt;p1&gt; [p2]</code></td><td>poweradminurt</td><td>Swap two players&#39; teams</td></tr><tr><td><code>!swap2</code> / <code>!swap3</code></td><td>poweradminurt</td><td>Auto-balance swap</td></tr><tr><td><code>!balance</code></td><td>poweradminurt</td><td>Auto-balance teams</td></tr><tr><td><code>!veto</code></td><td>poweradminurt</td><td>Veto current vote</td></tr><tr><td><code>!swapteams</code></td><td>poweradminurt</td><td>Swap entire teams</td></tr><tr><td><code>!shuffleteams</code></td><td>poweradminurt</td><td>Shuffle teams randomly</td></tr><tr><td><code>!muteall &lt;on/off&gt;</code></td><td>poweradminurt</td><td>Mute/unmute all</td></tr><tr><td><code>!captain [player]</code></td><td>poweradminurt</td><td>Set captain (match mode)</td></tr><tr><td><code>!sub [player]</code></td><td>poweradminurt</td><td>Set substitute (match mode)</td></tr><tr><td><code>!lock</code> / <code>!unlock</code></td><td>poweradminurt</td><td>Lock/unlock team assignments</td></tr></tbody></table><h2 id="senior-admin-level-60" tabindex="-1">Senior Admin (Level 60) <a class="header-anchor" href="#senior-admin-level-60" aria-label="Permalink to &quot;Senior Admin (Level 60)&quot;">​</a></h2><p>Can permanently ban and configure server settings.</p><table tabindex="0"><thead><tr><th>Command</th><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><code>!ban &lt;player&gt; [reason]</code></td><td>admin</td><td>Permanent ban</td></tr><tr><td><code>!permban &lt;player&gt; [reason]</code></td><td>admin</td><td>Permanent ban (explicit)</td></tr><tr><td><code>!unban &lt;name or @id&gt;</code></td><td>admin</td><td>Unban a player</td></tr><tr><td><code>!say &lt;message&gt;</code></td><td>admin</td><td>Public server message</td></tr><tr><td><code>!scream &lt;message&gt;</code></td><td>admin</td><td>Bigtext to server</td></tr><tr><td><code>!longlist</code></td><td>admin</td><td>Detailed player list with IPs</td></tr><tr><td><code>!warnclear &lt;player&gt;</code></td><td>admin</td><td>Clear all warnings</td></tr><tr><td><code>!kickall &lt;pattern&gt; [reason]</code></td><td>admin</td><td>Kick all matching players</td></tr><tr><td><code>!banall &lt;pattern&gt; [reason]</code></td><td>admin</td><td>Ban all matching players</td></tr><tr><td><code>!spankall &lt;pattern&gt; [reason]</code></td><td>admin</td><td>Spank all matching players</td></tr><tr><td><code>!mask [player] [level]</code></td><td>admin</td><td>Mask player&#39;s level</td></tr><tr><td><code>!unmask [player]</code></td><td>admin</td><td>Remove level mask</td></tr><tr><td><code>!makereg &lt;player&gt;</code></td><td>admin</td><td>Promote to Regular</td></tr><tr><td><code>!unreg &lt;player&gt;</code></td><td>admin</td><td>Demote to User</td></tr><tr><td><code>!gear [+/-weapon]</code></td><td>poweradminurt</td><td>Manage allowed gear</td></tr><tr><td><code>!skins &lt;on/off&gt;</code></td><td>poweradminurt</td><td>Toggle client skins</td></tr><tr><td><code>!funstuff &lt;on/off&gt;</code></td><td>poweradminurt</td><td>Toggle funstuff</td></tr><tr><td><code>!goto &lt;on/off&gt;</code></td><td>poweradminurt</td><td>Toggle goto</td></tr><tr><td><code>!instagib &lt;on/off&gt;</code></td><td>poweradminurt</td><td>Toggle instagib</td></tr><tr><td><code>!hardcore &lt;on/off&gt;</code></td><td>poweradminurt</td><td>Toggle hardcore</td></tr><tr><td><code>!randomorder &lt;on/off&gt;</code></td><td>poweradminurt</td><td>Toggle random order</td></tr><tr><td><code>!stamina &lt;mode&gt;</code></td><td>poweradminurt</td><td>Set stamina mode</td></tr><tr><td><code>!moon &lt;on/off&gt;</code></td><td>poweradminurt</td><td>Toggle low gravity</td></tr><tr><td><code>!public [password]</code></td><td>poweradminurt</td><td>Set server public/password</td></tr><tr><td><code>!waverespawns &lt;on/off&gt;</code></td><td>poweradminurt</td><td>Toggle wave respawns</td></tr><tr><td><code>!respawngod &lt;on/off&gt;</code></td><td>poweradminurt</td><td>Toggle respawn protection</td></tr><tr><td><code>!respawndelay [secs]</code></td><td>poweradminurt</td><td>Get/set respawn delay</td></tr><tr><td><code>!caplimit [num]</code></td><td>poweradminurt</td><td>Get/set capture limit</td></tr><tr><td><code>!fraglimit [num]</code></td><td>poweradminurt</td><td>Get/set frag limit</td></tr><tr><td><code>!timelimit [mins]</code></td><td>poweradminurt</td><td>Get/set time limit</td></tr><tr><td><code>!hotpotato [val]</code></td><td>poweradminurt</td><td>Get/set hot potato</td></tr><tr><td><code>!setnextmap &lt;map&gt;</code></td><td>poweradminurt</td><td>Set next map</td></tr><tr><td><code>!maplist</code></td><td>poweradminurt</td><td>List available maps</td></tr><tr><td><code>!cyclemap</code></td><td>poweradminurt</td><td>Cycle to next map</td></tr><tr><td><code>!mapreload</code></td><td>poweradminurt</td><td>Reload current map</td></tr><tr><td><code>!maprestart</code></td><td>poweradminurt</td><td>Restart current map</td></tr><tr><td><code>!matchon</code> / <code>!matchoff</code></td><td>poweradminurt</td><td>Enable/disable match mode</td></tr><tr><td><code>!lms</code> / <code>!jump</code> / <code>!freeze</code> / <code>!gungame</code></td><td>poweradminurt</td><td>Set gametype</td></tr></tbody></table><h2 id="super-admin-level-80" tabindex="-1">Super Admin (Level 80) <a class="header-anchor" href="#super-admin-level-80" aria-label="Permalink to &quot;Super Admin (Level 80)&quot;">​</a></h2><p>Full access to all commands.</p><table tabindex="0"><thead><tr><th>Command</th><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><code>!putgroup &lt;player&gt; &lt;group&gt;</code></td><td>admin</td><td>Set player&#39;s group</td></tr><tr><td><code>!ungroup &lt;player&gt;</code></td><td>admin</td><td>Remove from all groups</td></tr><tr><td><code>!map &lt;mapname&gt;</code></td><td>admin</td><td>Change map</td></tr><tr><td><code>!maps</code></td><td>admin</td><td>List available maps</td></tr><tr><td><code>!nextmap</code></td><td>admin</td><td>Show next map</td></tr><tr><td><code>!maprotate</code></td><td>admin</td><td>Cycle to next map</td></tr><tr><td><code>!die</code></td><td>admin</td><td>Shut down R3</td></tr><tr><td><code>!restart</code></td><td>admin</td><td>Restart R3</td></tr><tr><td><code>!reconfig</code></td><td>admin</td><td>Reload configuration</td></tr><tr><td><code>!pause</code></td><td>admin</td><td>Pause log parsing</td></tr><tr><td><code>!rebuild</code></td><td>admin</td><td>Re-sync client list</td></tr><tr><td><code>!runas &lt;player&gt; &lt;command&gt;</code></td><td>admin</td><td>Run command as another player</td></tr><tr><td><code>!iamgod</code></td><td>admin</td><td>Promote self to Super Admin (first time only)</td></tr><tr><td><code>!set &lt;cvar&gt; &lt;value&gt;</code></td><td>poweradminurt</td><td>Set any server cvar</td></tr><tr><td><code>!get &lt;cvar&gt;</code></td><td>poweradminurt</td><td>Get any server cvar</td></tr><tr><td><code>!exec &lt;configfile&gt;</code></td><td>poweradminurt</td><td>Execute config file</td></tr></tbody></table><h2 id="group-names" tabindex="-1">Group Names <a class="header-anchor" href="#group-names" aria-label="Permalink to &quot;Group Names&quot;">​</a></h2><p>For <code>!putgroup</code>, use these group keywords:</p><table tabindex="0"><thead><tr><th>Keyword</th><th>Level</th></tr></thead><tbody><tr><td><code>guest</code></td><td>0</td></tr><tr><td><code>user</code></td><td>1</td></tr><tr><td><code>regular</code> / <code>reg</code></td><td>2</td></tr><tr><td><code>mod</code> / <code>moderator</code></td><td>20</td></tr><tr><td><code>admin</code></td><td>40</td></tr><tr><td><code>senioradmin</code> / <code>senior</code></td><td>60</td></tr><tr><td><code>superadmin</code> / <code>super</code></td><td>80</td></tr></tbody></table><h2 id="duration-format" tabindex="-1">Duration Format <a class="header-anchor" href="#duration-format" aria-label="Permalink to &quot;Duration Format&quot;">​</a></h2><p>For <code>!tempban</code>, durations can be specified as:</p><table tabindex="0"><thead><tr><th>Format</th><th>Example</th><th>Duration</th></tr></thead><tbody><tr><td><code>Nm</code></td><td><code>30m</code></td><td>30 minutes</td></tr><tr><td><code>Nh</code></td><td><code>2h</code></td><td>2 hours</td></tr><tr><td><code>Nd</code></td><td><code>7d</code></td><td>7 days</td></tr><tr><td><code>Nw</code></td><td><code>2w</code></td><td>2 weeks</td></tr></tbody></table><p>Default duration (when omitted): <strong>2 hours</strong>.</p>',27)])])}const g=d(a,[["render",n]]);export{u as __pageData,g as default};
